438ŌåÆ		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
439ŌåÆ		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
440ŌåÆ		const brand = this.detectBrand({ text: sanitizedQuery });
441ŌåÆ		const detectedColor = this.detectColor({ text: sanitizedQuery });
442ŌåÆ		const detectedSize = this.detectSize({ text: sanitizedQuery });
443ŌåÆ		const detectedPriceRange = this.detectPriceRange({ text: queryText });
444ŌåÆ
445ŌåÆ		const baseFilters: object[] = [{ term: { status: 'active' } }];
446ŌåÆ
447ŌåÆ		const genderBoosts: object[] = genderProductTypes
448ŌåÆ			? [{ terms: { product_type: genderProductTypes } }]
449ŌåÆ			: [];
450ŌåÆ
451ŌåÆ		const priceBoosts: object[] =
452ŌåÆ			priceLevels?.map((level) => ({
453ŌåÆ				term: { price_level: { value: level } },
454ŌåÆ			})) ?? [];
455ŌåÆ
456ŌåÆ		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand] } }] : [];
457ŌåÆ
458ŌåÆ		const colorBoosts: object[] = detectedColor
459ŌåÆ			? [
460ŌåÆ					{
461ŌåÆ						nested: {
462ŌåÆ							path: 'colors',
463ŌåÆ							query: {
464ŌåÆ								wildcard: {
465ŌåÆ									'colors.name': {
466ŌåÆ										value: `*${detectedColor.toLowerCase()}*`,
467ŌåÆ										case_insensitive: true,
468ŌåÆ									},
469ŌåÆ								},
470ŌåÆ							},
471ŌåÆ						},
472ŌåÆ					},
473ŌåÆ				]
474ŌåÆ			: [];
475ŌåÆ
476ŌåÆ		const unitPriceBoosts: object[] = detectedPriceRange
477ŌåÆ			? [
478ŌåÆ					{
479ŌåÆ						range: {
480ŌåÆ							price: {
481ŌåÆ								...(detectedPriceRange.min !== null && { gte: detectedPriceRange.min }),
482ŌåÆ								...(detectedPriceRange.max !== null && { lte: detectedPriceRange.max }),
483ŌåÆ							},
484ŌåÆ						},
485ŌåÆ					},
486ŌåÆ				]
487ŌåÆ			: [];
488ŌåÆ
489ŌåÆ		const sizeBoosts: object[] = detectedSize
490ŌåÆ			? [
491ŌåÆ					{
492ŌåÆ						wildcard: {
493ŌåÆ							sizes: { value: `*${detectedSize.toLowerCase()}*`, case_insensitive: true },
494ŌåÆ						},
495ŌåÆ					},
496ŌåÆ				]
497ŌåÆ			: [];
498ŌåÆ
499ŌåÆ		const hits = await this.opensearchService.search({
500ŌåÆ			indexName: this.indexName,
501ŌåÆ			searchPipeline: 'hybrid-search-pipeline',
502ŌåÆ			body: {
503ŌåÆ				size,
504ŌåÆ				min_score: 0.4,
505ŌåÆ				query: {
506ŌåÆ					hybrid: {
507ŌåÆ						queries: [
508ŌåÆ							{
509ŌåÆ								bool: {
510ŌåÆ									should: [
511ŌåÆ										...priceBoosts,
512ŌåÆ										...brandBoosts,
513ŌåÆ										...genderBoosts,
514ŌåÆ										...colorBoosts,
515ŌåÆ										// ...sizeBoosts,
516ŌåÆ										...unitPriceBoosts,
517ŌåÆ									],
518ŌåÆ									filter: baseFilters,
519ŌåÆ								},
520ŌåÆ							},
521ŌåÆ							{
522ŌåÆ								neural: {
523ŌåÆ									product_embedding: {
524ŌåÆ										query_text: normalizedQuery,
525ŌåÆ										model_id: this.getModelId(),
526ŌåÆ										k: size * 5,
527ŌåÆ										filter: { bool: { filter: baseFilters } },
528ŌåÆ									},
529ŌåÆ								},
530ŌåÆ							},
531ŌåÆ						],
532ŌåÆ					},
533ŌåÆ				},
534ŌåÆ				collapse: { field: 'product_id' },
535ŌåÆ				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
536ŌåÆ			},
537ŌåÆ		});
538ŌåÆ
539ŌåÆ		const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
540ŌåÆ
541ŌåÆ		return hits.map((hit) => {
542ŌåÆ			const product = hit._source as IOpensearchProduct;
543ŌåÆ			const imageUrl = detectedColor
