548ŌåÆ			return {
549ŌåÆ				...product,
550ŌåÆ				_id: hit._id,
551ŌåÆ				confidenceScore: Math.min(Math.round(Math.pow(normalizedScore, 2) * 100), 100),
552ŌåÆ				...(imageUrl !== null && { style_card_image_url: imageUrl }),
553ŌåÆ			};
554ŌåÆ		});
555ŌåÆ	}
